import{_ as s,o as e,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"设置","description":"","frontmatter":{"read_when":["设置新机器","你想要\\"最新最好的\\"而不破坏你的个人设置"],"summary":"设置指南：在保持最新的同时保持你的 OpenSoul 设置个性化","title":"设置","x-i18n":{"generated_at":"2026-02-03T07:54:27Z","model":"claude-opus-4-5","provider":"pi","source_hash":"b7f4bd657d0df4feb5035c9f5ee727f9c67b991e9cedfc7768f99d010553fa01","source_path":"start/setup.md","workflow":15}},"headers":[],"relativePath":"zh-CN/start/setup.md","filePath":"zh-CN/start/setup.md","lastUpdated":null}'),l={name:"zh-CN/start/setup.md"};function t(o,a,d,p,r,c){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="设置" tabindex="-1"><a class="header-anchor" href="#设置">#</a> 设置</h1><p>最后更新：2026-01-01</p><h2 id="太长不看" tabindex="-1"><a class="header-anchor" href="#太长不看">#</a> 太长不看</h2><ul><li><strong>个性化设置存放在仓库之外：</strong> <code>~/.opensoul/workspace</code>（工作区）+ <code>~/.opensoul/opensoul.json</code>（配置）。</li><li><strong>稳定工作流：</strong> 安装 macOS 应用；让它运行内置的 Gateway 网关。</li><li><strong>前沿工作流：</strong> 通过 <code>pnpm gateway:watch</code> 自己运行 Gateway 网关，然后让 macOS 应用以本地模式连接。</li></ul><h2 id="先决条件-从源码" tabindex="-1"><a class="header-anchor" href="#先决条件-从源码">#</a> 先决条件（从源码）</h2><ul><li>Node <code>&gt;=22</code></li><li><code>pnpm</code></li><li>Docker（可选；仅用于容器化设置/e2e — 参阅 <a href="/docs/install/docker">Docker</a>）</li></ul><h2 id="个性化策略-让更新不会造成问题" tabindex="-1"><a class="header-anchor" href="#个性化策略-让更新不会造成问题">#</a> 个性化策略（让更新不会造成问题）</h2><p>如果你想要&quot;100% 为我定制&quot;<em>并且</em>易于更新，将你的自定义内容保存在：</p><ul><li><strong>配置：</strong> <code>~/.opensoul/opensoul.json</code>（JSON/JSON5 格式）</li><li><strong>工作区：</strong> <code>~/.opensoul/workspace</code>（Skills、提示、记忆；将其设为私有 git 仓库）</li></ul><p>引导一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在此仓库内部，使用本地 CLI 入口：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你还没有全局安装，通过 <code>pnpm opensoul setup</code> 运行它。</p><h2 id="稳定工作流-macos-应用优先" tabindex="-1"><a class="header-anchor" href="#稳定工作流-macos-应用优先">#</a> 稳定工作流（macOS 应用优先）</h2><ol><li>安装并启动 <strong>OpenSoul.app</strong>（菜单栏）。</li><li>完成新手引导/权限检查清单（TCC 提示）。</li><li>确保 Gateway 网关是<strong>本地</strong>并正在运行（应用管理它）。</li><li>链接表面（示例：WhatsApp）：</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="5"><li>完整性检查：</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你的构建版本中没有新手引导：</p><ul><li>运行 <code>opensoul setup</code>，然后 <code>opensoul channels login</code>，然后手动启动 Gateway 网关（<code>opensoul gateway</code>）。</li></ul><h2 id="前沿工作流-在终端中运行-gateway-网关" tabindex="-1"><a class="header-anchor" href="#前沿工作流-在终端中运行-gateway-网关">#</a> 前沿工作流（在终端中运行 Gateway 网关）</h2><p>目标：开发 TypeScript Gateway 网关，获得热重载，保持 macOS 应用 UI 连接。</p><h3 id="_0-可选-也从源码运行-macos-应用" tabindex="-1"><a class="header-anchor" href="#_0-可选-也从源码运行-macos-应用">#</a> 0)（可选）也从源码运行 macOS 应用</h3><p>如果你也想让 macOS 应用保持前沿：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/restart-mac.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_1-启动开发-gateway-网关" tabindex="-1"><a class="header-anchor" href="#_1-启动开发-gateway-网关">#</a> 1) 启动开发 Gateway 网关</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>gateway:watch</code> 以监视模式运行 Gateway 网关，并在 TypeScript 更改时重新加载。</p><h3 id="_2-将-macos-应用指向你正在运行的-gateway-网关" tabindex="-1"><a class="header-anchor" href="#_2-将-macos-应用指向你正在运行的-gateway-网关">#</a> 2) 将 macOS 应用指向你正在运行的 Gateway 网关</h3><p>在 <strong>OpenSoul.app</strong> 中：</p><ul><li>连接模式：<strong>本地</strong> 应用将连接到在配置端口上运行的 Gateway 网关。</li></ul><h3 id="_3-验证" tabindex="-1"><a class="header-anchor" href="#_3-验证">#</a> 3) 验证</h3><ul><li>应用内 Gateway 网关状态应显示 <strong>&quot;Using existing gateway …&quot;</strong></li><li>或通过 CLI：</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="常见陷阱" tabindex="-1"><a class="header-anchor" href="#常见陷阱">#</a> 常见陷阱</h3><ul><li><strong>端口错误：</strong> Gateway 网关 WS 默认为 <code>ws://127.0.0.1:18789</code>；保持应用 + CLI 在同一端口上。</li><li><strong>状态存储位置：</strong><ul><li>凭证：<code>~/.opensoul/credentials/</code></li><li>会话：<code>~/.opensoul/agents/&lt;agentId&gt;/sessions/</code></li><li>日志：<code>/tmp/opensoul/</code></li></ul></li></ul><h2 id="凭证存储映射" tabindex="-1"><a class="header-anchor" href="#凭证存储映射">#</a> 凭证存储映射</h2><p>在调试认证或决定备份什么时使用此映射：</p><ul><li><strong>WhatsApp</strong>：<code>~/.opensoul/credentials/whatsapp/&lt;accountId&gt;/creds.json</code></li><li><strong>Telegram bot token</strong>：配置/环境变量或 <code>channels.telegram.tokenFile</code></li><li><strong>Discord bot token</strong>：配置/环境变量（尚不支持令牌文件）</li><li><strong>Slack tokens</strong>：配置/环境变量（<code>channels.slack.*</code>）</li><li><strong>配对允许列表</strong>：<code>~/.opensoul/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>模型认证配置文件</strong>：<code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li><strong>旧版 OAuth 导入</strong>：<code>~/.opensoul/credentials/oauth.json</code> 更多详情：<a href="/docs/gateway/security/index#credential-storage-map">安全</a>。</li></ul><h2 id="更新-不破坏你的设置" tabindex="-1"><a class="header-anchor" href="#更新-不破坏你的设置">#</a> 更新（不破坏你的设置）</h2><ul><li>将 <code>~/.opensoul/workspace</code> 和 <code>~/.opensoul/</code> 保持为&quot;你的东西&quot;；不要将个人提示/配置放入 <code>opensoul</code> 仓库。</li><li>更新源码：<code>git pull</code> + <code>pnpm install</code>（当锁文件更改时）+ 继续使用 <code>pnpm gateway:watch</code>。</li></ul><h2 id="linux-systemd-用户服务" tabindex="-1"><a class="header-anchor" href="#linux-systemd-用户服务">#</a> Linux（systemd 用户服务）</h2><p>Linux 安装使用 systemd <strong>用户</strong>服务。默认情况下，systemd 在注销/空闲时停止用户服务，这会终止 Gateway 网关。新手引导会尝试为你启用 lingering（可能提示 sudo）。如果仍然关闭，运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loginctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable-linger</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $USER</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>对于常驻或多用户服务器，考虑使用<strong>系统</strong>服务而不是用户服务（不需要 lingering）。参阅 <a href="/docs/gateway/index">Gateway 网关运行手册</a> 了解 systemd 说明。</p><h2 id="相关文档" tabindex="-1"><a class="header-anchor" href="#相关文档">#</a> 相关文档</h2><ul><li><a href="/docs/gateway/index">Gateway 网关运行手册</a>（标志、监督、端口）</li><li><a href="/docs/gateway/configuration">Gateway 网关配置</a>（配置模式 + 示例）</li><li><a href="/docs/channels/discord">Discord</a> 和 <a href="/docs/channels/telegram">Telegram</a>（回复标签 + replyToMode 设置）</li><li><a href="/docs/start/opensoul">OpenSoul 助手设置</a></li><li><a href="/docs/platforms/macos">macOS 应用</a>（Gateway 网关生命周期）</li></ul>`,48)])])}const g=s(l,[["render",t]]);export{u as __pageData,g as default};
